tests.source_program:
define <vscale x 2 x i1> @dont_crash(<vscale x 2 x i64> %x) {
entry:
  %div = sdiv <vscale x 2 x i64> %x, shufflevector (<vscale x 2 x i64> insertelement (<vscale x 2 x i64> poison, i64 309383, i64 0), <vscale x 2 x i64> poison, <vscale x 2 x i32> zeroinitializer)
  %ret = icmp sge <vscale x 2 x i64> %div, zeroinitializer
  ret <vscale x 2 x i1> %ret
}

target datalayout = "e-p:64:64-p1:16:16-p2:32:32:32-p3:64:64:64"

define <vscale x 2 x i32> @scalable_sign_bits(<vscale x 2 x i8> %x) {
  %a = sext <vscale x 2 x i8> %x to <vscale x 2 x i32>
  %b = shl <vscale x 2 x i32> %a, shufflevector (<vscale x 2 x i32> insertelement (<vscale x 2 x i32> poison, i32 16, i64 0), <vscale x 2 x i32> poison, <vscale x 2 x i32> zeroinitializer)
  ret <vscale x 2 x i32> %b
}

define <vscale x 2 x i1> @sge(<vscale x 2 x i8> %x) {
  %cmp = icmp sge <vscale x 2 x i8> %x, zeroinitializer
  ret <vscale x 2 x i1> %cmp
}
